from dataclasses import dataclass
from datetime import datetime, timezone
from enum import Enum
import re

class TemplateId(str, Enum):
    GENERAL_OUTAGE      = "TEMPL-1"
    QUALITY_DEGRADATION = "TEMPL-2"
    MINOR_OUTAGE        = "TEMPL-3"
    PRIVACY_INCIDENT    = "TEMPL-4"

@dataclass
class CommsPackage:
    template_id: TemplateId
    incident_id: str
    fields: dict[str, str]
    ic_approved_at: datetime | None = None
    legal_approved_at: datetime | None = None  # required for TEMPL-4

def render_template(package: CommsPackage) -> str:
    TEMPLATES = {
        TemplateId.GENERAL_OUTAGE: TEMPL_1,
        TemplateId.QUALITY_DEGRADATION: TEMPL_2,
        TemplateId.MINOR_OUTAGE: TEMPL_3,
        TemplateId.PRIVACY_INCIDENT: TEMPL_4,
    }
    template = TEMPLATES[package.template_id]
    missing = [k for k in re.findall(r'\{(\w+)\}', template) if k not in package.fields]
    if missing:
        raise ValueError(f"Missing required fields: {missing}")
    return template.format(**package.fields)

def validate_approval(package: CommsPackage) -> None:
    if package.ic_approved_at is None:
        raise PermissionError("IC approval required before dispatch")
    if package.template_id == TemplateId.PRIVACY_INCIDENT:
        if package.legal_approved_at is None:
            raise PermissionError("Legal approval required for TEMPL-4")

def dispatch_comms(package: CommsPackage, channel: str) -> dict:
    validate_approval(package)
    body = render_template(package)
    if channel == "status_page":
        return post_status_page_incident(package.incident_id, body)
    elif channel == "email":
        return send_customer_email(
            subject=extract_subject_line(body),
            body_markdown=body,
            audience=resolve_audience(package.template_id, package.incident_id),
        )
    raise ValueError(f"Unknown channel: {channel}")

PROHIBITED_PHRASES = [
    "no evidence of misuse",
    "minimal impact",
    "user error",
    "isolated incident",
    "all systems normal",   # never true mid-incident
    "as soon as possible",  # vague; give a concrete time
]

def lint_draft(draft: str) -> list[str]:
    warnings = []
    for phrase in PROHIBITED_PHRASES:
        if phrase.lower() in draft.lower():
            warnings.append(f"Prohibited phrase detected: '{phrase}'")
    if re.search(r'\{[a-z_]+\}', draft):
        warnings.append("Unfilled template placeholder detected")
    if "next update" not in draft.lower():
        warnings.append("Missing 'next update' time commitment")
    return warnings

